/* Detectar duplicado entre productos críticos (desde Consultar stock crítico)
   y notificaciones sin leer (entrada actual).
   El backend devuelve { ok, notificaciones: [...], totalNoLeidas } — accedemos a .notificaciones
   La comparación usa productId (campo guardado en el modelo) contra _id del producto.
   Salida:
     - { enviar: false, motivo: 'duplicado', notificaciones: [...] }  <-- si ya existe
     - { enviar: true, productosCriticos: [...] }                   <-- si no existe duplicado
*/
const productosResp = $node["Consultar stock crítico"].json;
const productos = Array.isArray(productosResp) ? productosResp : ((productosResp && productosResp.body) || []);
const notifs = $input.item.json || {};
// El endpoint /webhook/no-leidas devuelve { ok, notificaciones: [...], totalNoLeidas }
const notifsArray = Array.isArray(notifs) ? notifs : (notifs.notificaciones || notifs.body || []);

function contieneProducto(notifProductos, productosCriticos) {
  if (!Array.isArray(notifProductos) || !Array.isArray(productosCriticos)) return false;
  return productosCriticos.some(p =>
    notifProductos.some(np =>
      (np.productId && np.productId.toString() === p._id.toString()) ||
      (np._id && np._id.toString() === p._id.toString())
    )
  );
}

let existeDuplicado = false;
if (Array.isArray(notifsArray)) {
  for (const n of notifsArray) {
    const prodNotif = n.productos || [];
    if (contieneProducto(prodNotif, productos)) {
      existeDuplicado = true;
      break;
    }
  }
}

if (existeDuplicado) {
  return [{ json: { enviar: false, motivo: 'duplicado', notificaciones: notifsArray } }];
}

// No hay duplicado -> avanzamos con los productos críticos
return [{ json: { enviar: true, productosCriticos: productos } }];

/* Prepara datos de stock crítico para enviar al admin
   Entrada: $json.productosCriticos (array completo desde getStockCritico, incluye descripcion)
   Salida: { mensaje, productos, tipo, enviar, cantidad }
*/
const productosCriticos = $json.productosCriticos || [];
if (!Array.isArray(productosCriticos) || productosCriticos.length === 0) {
  return [{ json: { error: 'Sin productos críticos', enviar: false } }];
}

const productosFormato = productosCriticos.map(p => ({
  _id: p._id,
  nombre: p.nombre,
  descripcion: p.descripcion || '',
  stock: p.stock,
  umbral: p.umbral ?? 5,
  precio: p.precio
}));

const productosDetalle = productosCriticos
  .map(p => `${p.nombre} (Stock: ${p.stock}${p.descripcion ? ' — ' + p.descripcion : ''})`)
  .join('; ');
const mensaje = `⚠️ STOCK CRÍTICO DETECTADO: ${productosCriticos.length} producto(s) requieren revisión inmediata. Productos: ${productosDetalle}`;

return [{ json: { 
  mensaje, 
  productos: productosFormato, 
  tipo: 'stock_critico',
  enviar: true,
  cantidad: productosCriticos.length
} }];

/* Normaliza el body del webhook: extrae decision e idNotificacion al nivel raíz */
const data = $json.body || $json;
const decision = data.decision || '';
const idNotificacion = data.idNotificacion || data.id || '';
if (!idNotificacion) {
  throw new Error('idNotificacion no recibido en el webhook');
}
return [{ json: { decision, idNotificacion } }];

/* Gatekeeper de errores HTTP.
   Si la respuesta es un error conocido, detiene la ejecución (devuelve array vacío).
   Si todo está bien, pasa los datos sin modificar al siguiente nodo.
*/
const resp = $input.item.json || {};
if (resp.statusCode === 401 || resp.code === 401 || resp.error === 'Unauthorized') {
  console.error('❌ Error 401: Sin autorización');
  return [];
}
if (resp.statusCode === 500 || resp.error === 'Internal Server Error' || (resp.ok === false && resp.error)) {
  console.error('❌ Error en respuesta HTTP:', JSON.stringify(resp));
  return [];
}
// Pasar datos sin modificar
return [$input.item];

/* Genera el RESUMEN DE EJECUCIÓN final según especificación */
const fecha = $now.format('DD/MM/YYYY HH:mm','America/Guayaquil');
const productosRevisados = Array.isArray($json.productosRevisados) ? $json.productosRevisados.length : ($json.productosCriticos ? $json.productosCriticos.length : 0);
const productosCriticos = $json.productosCriticos ? $json.productosCriticos.length : 0;
const notificacionEnviada = $json.notificacionId ? 'Sí' : 'No';
const aprobacion = $json.aprobacion === 'aprobado' ? 'Aprobado' : ($json.aprobacion === 'rechazado' ? 'Rechazado' : 'Pendiente');
const emailEnviado = $json.emailEnviado ? 'Enviado' : 'No enviado';
const estadoFinal = $json.estadoFinal || (aprobacion === 'Aprobado' && emailEnviado === 'Enviado' ? 'Completado' : 'Cancelado');

const resumen = `RESUMEN DE EJECUCIÓN — ${fecha}\n─────────────────────────────────────\nProductos revisados: ${productosRevisados}\nProductos críticos encontrados: ${productosCriticos}\nNotificación enviada al admin: ${notificacionEnviada}\nAprobación del admin: ${aprobacion}\nEmail al proveedor: ${emailEnviado}\nEstado final: ${estadoFinal}\n─────────────────────────────────────`;

return [{ json: { resumen, fecha, productosRevisados, productosCriticos, notificacionEnviada, aprobacion, emailEnviado, estadoFinal } }];
